noncompliant:
void func(int n, int m) {
  switch (n) {
    case 1:
      switch (m) {  // Noncompliant: nested switch
        case 10:
          doSomething();
          break;
        case 20:
          doOtherThing();
          break;
      }
      break;
    case 2:
      // ...
      break;
  }
}

compliant:
void handleCase1(int m) {
  switch (m) {
    case 10:
      doSomething();
      break;
    case 20:
      doOtherThing();
      break;
  }
}

void func(int n, int m) {
  switch (n) {
    case 1:
      handleCase1(m);
      break;
    case 2:
      // ...
      break;
  }
}

void func(int n, int m) {
  if (n == 1) {
    if (m == 10) {
      doSomething();
    } else if (m == 20) {
      doOtherThing();
    }
  } else if (n == 2) {
    // ...
  }
}
